class Solution:
    def getMaxRepetitions(self, s1: str, n1: int, s2: str, n2: int) -> int:
        if not s2:
            return float('inf') if not s1 else 0

        s1_count = {}
        s2_count = {}
        s1_ptr, s2_ptr = 0, 0
        count = 0

        for _ in range(n1):
            if s1_ptr == len(s1):
                s1_ptr = 0
            if s1[s1_ptr] == s2[s2_ptr]:
                s2_ptr += 1
                count += 1
            s1_ptr += 1
            if s2_ptr == len(s2):
                s2_ptr = 0
                count += 1

        if count == 0:
            return 0

        s1_cycle = {}
        s2_cycle = {}
        s1_ptr, s2_ptr = 0, 0
        cycle_count = 0
        for _ in range(len(s1) * len(s2)):
            if s1_ptr == len(s1):
                s1_ptr = 0
            if s2_ptr == len(s2):
                s2_ptr = 0
                cycle_count += 1
            if (s1_ptr, s2_ptr) in s1_cycle:
                cycle_len = cycle_count - s1_cycle[(s1_ptr, s2_ptr)][1]
                cycle_match = s1_cycle[(s1_ptr, s2_ptr)][0] - count
                return (n1 * count - cycle_match) // cycle_match * cycle_len + (n1 * count - cycle_match) % cycle_match // cycle_len + 1
            s1_cycle[(s1_ptr, s2_ptr)] = (count, cycle_count)
            if s1[s1_ptr] == s2[s2_ptr]:
                s2_ptr += 1
                count += 1
            s1_ptr += 1

        return n1 * count // len(s2) // n2
